module RefModule (  
    input wire clk,  
    input wire reset,  
    input wire [3:0] timeout_value,  
    output reg timeout_signal  
);  
    reg [3:0] unused_counter;  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            unused_counter <= 4'b0000;  
            timeout_signal <= 1'b0;  
        end else begin  
            if (unused_counter < timeout_value) begin  
                unused_counter <= unused_counter + 1;  
                timeout_signal <= 1'b0;  
            end else begin  
                timeout_signal <= 1'b1;  
            end  
        end  
    end  
endmodule
